import org.springframework.data.redis.core.RedisTemplate;
import org.springframework.stereotype.Service;
import java.time.Duration;

@Service
public class BasicRateLimiter {
    private final RedisTemplate<String, String> redis;

    BasicRateLimiter(RedisTemplate<String,String> r) { redis = r; }

    private long currentWindow() {
        return System.currentTimeMillis() / 60_000;
    }

    String getWindowKey(String userId) {
        return "rate:" + userId + ":" + currentWindow();
    }

    public boolean isAllowed(String userId, int maxPerMinute) {
        String key = getWindowKey(userId);
        Long count = redis.opsForValue().increment(key);
        if (count == 1) {
            redis.expire(key, Duration.ofMinutes(2));
        }
        return count <= maxPerMinute;
    }

    public long getRemainingRequests(String userId, int maxPerMinute) {
        String key = getWindowKey(userId);
        Object val = redis.opsForValue().get(key);
        long used = val != null ? Long.parseLong(val.toString()) : 0;
        return Math.max(0, maxPerMinute - used);
    }

    public long secondsUntilReset() {
        long now = System.currentTimeMillis();
        long nextWindowMs = (currentWindow() + 1) * 60_000;
        return (nextWindowMs - now) / 1000;
    }
}

