import jakarta.servlet.*;
import jakarta.servlet.http.*;
import org.springframework.core.annotation.Order;
import org.springframework.stereotype.Component;
import java.io.IOException;

@Component
@Order(1)
public class RateLimitFilter implements Filter {
    private final BasicRateLimiter limiter;

    RateLimitFilter(BasicRateLimiter l) { limiter = l; }

    @Override
    public void doFilter(ServletRequest req, ServletResponse res, FilterChain chain)
            throws IOException, ServletException {

        HttpServletRequest  rq = (HttpServletRequest)  req;
        HttpServletResponse rs = (HttpServletResponse) res;

        String userId = rq.getHeader("X-User-Id");
        String identifier = userId != null
            ? "user:" + userId
            : "ip:" + rq.getRemoteAddr();
        int limit = userId != null ? 100 : 20;

        if (!limiter.isAllowed(identifier, limit)) {
            long retryAfter = limiter.secondsUntilReset();
            rs.setStatus(429);
            rs.setContentType("application/json");
            rs.setHeader("Retry-After",          String.valueOf(retryAfter));
            rs.setHeader("X-RateLimit-Limit",    String.valueOf(limit));
            rs.setHeader("X-RateLimit-Remaining","0");
            rs.getWriter().write(String.format(
                "{\"error\":\"Rate limit exceeded\",\"retryAfterSeconds\":%d}",
                retryAfter));
            return;  // ← CRITICAL: stop here, do NOT call chain.doFilter!
        }

        long remaining = limiter.getRemainingRequests(identifier, limit);
        rs.setHeader("X-RateLimit-Limit",    String.valueOf(limit));
        rs.setHeader("X-RateLimit-Remaining",String.valueOf(remaining));

        chain.doFilter(req, res);
    }
}

