import org.springframework.data.redis.core.RedisTemplate;
import org.springframework.stereotype.Service;
import java.time.Duration;
import java.util.Map;

@Service
public class EndpointRateLimiter {
    private final RedisTemplate<String, String> redis;

    // Endpoint patterns → limits (req/min):
    private static final Map<String, Integer> LIMITS = Map.of(
        "POST /api/orders",  5,
        "GET /api/orders",   60,
        "/api/products",    120,
        "/api/reports",      5
    );
    private static final int DEFAULT_LIMIT = 100;

    EndpointRateLimiter(RedisTemplate<String,String> r) { redis = r; }

    public boolean isAllowed(String userId, String method, String path) {
        int limit = resolveLimit(method, path);
        long window = System.currentTimeMillis() / 60_000;

        // Key includes method+path — separate counters per endpoint!
        String safeEndpoint = (method + path).replaceAll("[^a-zA-Z0-9]", "_");
        String key = "rate:" + userId + ":" + safeEndpoint + ":" + window;

        Long count = redis.opsForValue().increment(key);
        if (count == 1) redis.expire(key, Duration.ofMinutes(2));

        return count <= limit;
    }

    private int resolveLimit(String method, String path) {
        // Try method+path first:
        String methodPath = method + " " + path;
        if (LIMITS.containsKey(methodPath)) return LIMITS.get(methodPath);

        // Try path prefix:
        return LIMITS.entrySet().stream()
            .filter(e -> !e.getKey().startsWith("GET") && !e.getKey().startsWith("POST"))
            .filter(e -> path.startsWith(e.getKey()))
            .mapToInt(Map.Entry::getValue)
            .findFirst()
            .orElse(DEFAULT_LIMIT);
    }

    public static void main(String[] args) {
        System.out.println("POST /api/orders limit: 5/min");
        System.out.println("GET  /api/orders limit: 60/min");
        System.out.println("Different limits, different keys, independent counters");
    }
}

