import org.springframework.data.redis.core.RedisTemplate;
import org.springframework.stereotype.Service;
import java.time.Duration;

@Service
public class ZerodhaOrderThrottle {
    private static final int MAX_ORDERS_PER_SECOND = 3;
    private final RedisTemplate<String, String> redis;

    ZerodhaOrderThrottle(RedisTemplate<String,String> r) { redis = r; }

    // Second-level bucket instead of minute:
    private long currentSecond() {
        return System.currentTimeMillis() / 1_000;  // second since epoch
    }

    public boolean isOrderAllowed(String userId) {
        long second = currentSecond();
        String key = "rate:order:" + userId + ":" + second;  // 'rate:order:U001:1718476842'

        Long count = redis.opsForValue().increment(key);
        if (count == 1) {
            redis.expire(key, Duration.ofSeconds(2));  // 2s TTL: covers edge case
        }

        return count <= MAX_ORDERS_PER_SECOND;
    }

    public int remainingOrdersThisSecond(String userId) {
        String key = "rate:order:" + userId + ":" + currentSecond();
        Object val = redis.opsForValue().get(key);
        int used = val != null ? Integer.parseInt(val.toString()) : 0;
        return Math.max(0, MAX_ORDERS_PER_SECOND - used);
    }

    public static void main(String[] args) {
        // Second vs minute bucket:
        long now = System.currentTimeMillis();
        System.out.println("Minute bucket: " + (now / 60_000));
        System.out.println("Second bucket: " + (now / 1_000));
        System.out.println("Same principle, 60x finer granularity");
        // Key difference: second window expires in 2 seconds (not 2 minutes)
        // Much shorter window = much tighter control
        // SEBI compliant: no more than 3 orders within any 1-second window
    }
}

