import org.springframework.data.redis.core.RedisTemplate;
import org.springframework.stereotype.Service;
import jakarta.servlet.http.HttpServletResponse;
import java.time.Duration;

// Clean result record:
record RateLimitResult(
    boolean allowed,
    long    count,
    int     limit,
    long    remaining,
    long    resetInSeconds
) {}

@Service
public class RateLimitService {
    private final RedisTemplate<String, String> redis;

    RateLimitService(RedisTemplate<String,String> r) { redis = r; }

    public RateLimitResult check(String identifier, int limitPerMinute) {
        long window = System.currentTimeMillis() / 60_000;
        String key  = "rate:" + identifier + ":" + window;

        Long count = redis.opsForValue().increment(key);
        if (count == 1) redis.expire(key, Duration.ofMinutes(2));

        long remaining    = Math.max(0, limitPerMinute - count);
        long resetSeconds = ((window + 1) * 60_000 - System.currentTimeMillis()) / 1000;

        return new RateLimitResult(
            count <= limitPerMinute,  // allowed
            count,                    // current count
            limitPerMinute,           // configured limit
            remaining,                // requests left
            resetSeconds              // seconds until window resets
        );
    }
}

// Header enrichment utility:
class ResponseHeaderEnricher {
    static void enrich(HttpServletResponse rs, RateLimitResult r) {
        rs.setHeader("X-RateLimit-Limit",     String.valueOf(r.limit()));
        rs.setHeader("X-RateLimit-Remaining", String.valueOf(r.remaining()));
        rs.setHeader("X-RateLimit-Reset",     String.valueOf(r.resetInSeconds()));
        if (!r.allowed()) {
            rs.setHeader("Retry-After", String.valueOf(r.resetInSeconds()));
        }
    }
}

