import org.springframework.data.redis.core.RedisTemplate;
import org.springframework.stereotype.Service;
import java.time.Duration;

@Service
public class SlidingWindowRateLimiter {
    private final RedisTemplate<String, String> redis;

    SlidingWindowRateLimiter(RedisTemplate<String,String> r) { redis = r; }

    public boolean isAllowed(String identifier, int maxRequests, int windowSeconds) {
        String key = "sw:" + identifier;
        long now = System.currentTimeMillis();
        long windowStart = now - (windowSeconds * 1000L);

        // Step 1: Remove old entries (outside the sliding window):
        redis.opsForZSet().removeRangeByScore(key, 0, windowStart);

        // Step 2: Count requests still in the window:
        Long count = redis.opsForZSet().zCard(key);
        if (count != null && count >= maxRequests) {
            return false;  // limit already reached
        }

        // Step 3: Add this request (timestamp = score, unique value = timestamp+nano):
        String member = String.valueOf(now) + "-" + Thread.currentThread().getId();
        redis.opsForZSet().add(key, member, now);

        // Step 4: Set TTL for cleanup:
        redis.expire(key, Duration.ofSeconds(windowSeconds * 2L));

        return true;
    }

    // How many requests remain in the window:
    public long countInWindow(String identifier, int windowSeconds) {
        String key = "sw:" + identifier;
        long windowStart = System.currentTimeMillis() - (windowSeconds * 1000L);
        redis.opsForZSet().removeRangeByScore(key, 0, windowStart);
        Long count = redis.opsForZSet().zCard(key);
        return count != null ? count : 0;
    }

    public static void main(String[] args) {
        // Comparison:
        System.out.println("Fixed window: O(1) memory per user (1 key per minute)");
        System.out.println("Sliding window: O(N) memory per user (N = requests in window)");
        System.out.println("Sliding window: prevents boundary spike — better accuracy");
        System.out.println("Fixed window: lower memory, simpler — sufficient for most APIs");
    }
}

