    @Autowired org.springframework.data.redis.core.RedisTemplate<String,String> redis;

    // Use a unique test user per test run to avoid cross-test pollution:
    private final String testUserId = "test-" + System.currentTimeMillis();

    @BeforeEach void clearRateLimitKeys() {
        // Clean up any existing rate limit keys for this user:
        long window = System.currentTimeMillis() / 60_000;
        redis.delete("rate:user:" + testUserId + ":" + window);
    }

    @Test
    void first5Requests_return200() throws Exception {
        for (int i = 1; i <= 5; i++) {
            mvc.perform(get("/api/products")
                    .header("X-User-Id", testUserId))
                .andExpect(status().isOk())
                .andExpect(header().exists("X-RateLimit-Remaining"));
        }
    }

    @Test
    void request6_returns429() throws Exception {
        int limit = 5;  // must match filter's limit for this user type

        // Exhaust the limit:
        for (int i = 0; i < limit; i++) {
            mvc.perform(get("/api/products")
                    .header("X-User-Id", testUserId))
                .andExpect(status().isOk());
        }

        // 6th request: should be rate limited:
        mvc.perform(get("/api/products")
                .header("X-User-Id", testUserId))
            .andExpect(status().is(429))
            .andExpect(header().exists("Retry-After"))
            .andExpect(header().string("X-RateLimit-Remaining", "0"));
