        for (int i = 0; i < 5; i++) {
            mvc.perform(get("/api/products").header("X-User-Id", testUserId))
                .andExpect(status().isOk());
        }
        mvc.perform(get("/api/products").header("X-User-Id", testUserId))
            .andExpect(status().is(429))
            .andExpect(header().string("Retry-After",
                org.hamcrest.Matchers.matchesPattern("\\d+")));  // numeric string
    }
