import org.springframework.data.redis.core.RedisTemplate;
import org.springframework.stereotype.Service;
import java.time.Duration;

enum UserTier {
    FREE(20), PRO(100), ENTERPRISE(1000);
    final int requestsPerMinute;
    UserTier(int r) { requestsPerMinute = r; }
}

@Service
public class TieredRateLimitService {
    private final RedisTemplate<String, String> redis;

    TieredRateLimitService(RedisTemplate<String,String> r) { redis = r; }

    // Store user's tier in Redis Hash:
    public void setUserTier(String userId, UserTier tier) {
        redis.opsForHash().put("user:tiers", userId, tier.name());
    }

    // Get user's tier (default: FREE):
    public UserTier getUserTier(String userId) {
        Object val = redis.opsForHash().get("user:tiers", userId);
        if (val == null) return UserTier.FREE;
        try { return UserTier.valueOf(val.toString()); }
        catch (Exception e) { return UserTier.FREE; }
    }

    // Check rate limit for given tier:
    public boolean isAllowed(String userId, UserTier tier) {
        long window = System.currentTimeMillis() / 60_000;
        String key = "rate:" + tier.name() + ":" + userId + ":" + window;
        Long count = redis.opsForValue().increment(key);
        if (count == 1) redis.expire(key, Duration.ofMinutes(2));
        return count <= tier.requestsPerMinute;
    }

    // Combined: lookup tier from Redis, then check rate:
    public boolean isAllowedForUser(String userId) {
        UserTier tier = getUserTier(userId);
        return isAllowed(userId, tier);
    }

    public static void main(String[] args) {
        System.out.println("FREE:       20 req/min");
        System.out.println("PRO:       100 req/min");
        System.out.println("ENTERPRISE: 1000 req/min");
        System.out.println("FREE user: blocked on 21st request");
        System.out.println("PRO user:  allowed up to 100 requests");
    }
}

