import org.springframework.data.redis.core.RedisTemplate;
import org.springframework.stereotype.Service;
import java.time.Duration;

record DualRateLimitResult(boolean allowed, String limitType, long userCount, long globalCount) {}

@Service
public class DualRateLimiter {
    private static final int USER_LIMIT   = 100;
    private static final int GLOBAL_LIMIT = 10_000;

    private final RedisTemplate<String, String> redis;

    DualRateLimiter(RedisTemplate<String,String> r) { redis = r; }

    public DualRateLimitResult check(String userId) {
        long window = System.currentTimeMillis() / 60_000;

        // Per-user counter:
        String userKey   = "rate:user:" + userId + ":" + window;
        Long   userCount = redis.opsForValue().increment(userKey);
        if (userCount == 1) redis.expire(userKey, Duration.ofMinutes(2));

        // Global counter (same for ALL users, just the window key):
        String globalKey   = "rate:global:" + window;
        Long   globalCount = redis.opsForValue().increment(globalKey);
        if (globalCount == 1) redis.expire(globalKey, Duration.ofMinutes(2));

        // Check which limit is hit:
        if (userCount > USER_LIMIT) {
            return new DualRateLimitResult(false, "user", userCount, globalCount);
        }
        if (globalCount > GLOBAL_LIMIT) {
            return new DualRateLimitResult(false, "global", userCount, globalCount);
        }
        return new DualRateLimitResult(true, "none", userCount, globalCount);
    }

    public static void main(String[] args) {
        System.out.println("Per-user: 100/min (protects against individual abuse)");
        System.out.println("Global: 10,000/min (protects total system capacity)");
        System.out.println("Global is shared — if 100 users each make 100 req/min,");
        System.out.println("global counter = 10,000 → 101st user hits global limit");
    }
}

