import org.springframework.data.redis.core.RedisTemplate;
import org.springframework.stereotype.Service;
import org.springframework.web.bind.annotation.*;
import java.time.Duration;

@Service
public class RateLimitWithWhitelist {
    private static final String WHITELIST_KEY = "rate:whitelist";
    private final RedisTemplate<String, String> redis;

    RateLimitWithWhitelist(RedisTemplate<String,String> r) { redis = r; }

    // SADD rate:whitelist identifier
    public void addToWhitelist(String identifier) {
        redis.opsForSet().add(WHITELIST_KEY, identifier);
    }

    // SREM rate:whitelist identifier
    public void removeFromWhitelist(String identifier) {
        redis.opsForSet().remove(WHITELIST_KEY, identifier);
    }

    // SISMEMBER rate:whitelist identifier → true/false
    public boolean isWhitelisted(String identifier) {
        return Boolean.TRUE.equals(redis.opsForSet().isMember(WHITELIST_KEY, identifier));
    }

    // Rate check that respects whitelist:
    public boolean isAllowed(String identifier, int limit) {
        if (isWhitelisted(identifier)) {
            return true;  // bypass rate limit entirely
        }
        long window = System.currentTimeMillis() / 60_000;
        String key = "rate:" + identifier + ":" + window;
        Long count = redis.opsForValue().increment(key);
        if (count == 1) redis.expire(key, Duration.ofMinutes(2));
        return count <= limit;
    }
}

