    private static final int DEFAULT_LIMIT = 100;
    private final RedisTemplate<String, String> redis;

    RateLimitStatusService(RedisTemplate<String,String> r) { redis = r; }

    public Map<String, Object> getStatus(String identifier) {
        long window = System.currentTimeMillis() / 60_000;
        String key = "rate:" + identifier + ":" + window;

        Object val = redis.opsForValue().get(key);
        long count = val != null ? Long.parseLong(val.toString()) : 0;
        long remaining = Math.max(0, DEFAULT_LIMIT - count);
        long resetIn = ((window + 1) * 60_000 - System.currentTimeMillis()) / 1000;
        boolean throttled = count > DEFAULT_LIMIT;

        return Map.of(
            "identifier",        identifier,
            "requestsThisWindow", count,
            "limit",             DEFAULT_LIMIT,
            "remaining",         remaining,
            "resetInSeconds",    resetIn,
            "isThrottled",       throttled
        );
    }
}

@RestController
@RequestMapping("/api/rate-limit")
class RateLimitStatusController {
    private final RateLimitStatusService statusService;
    RateLimitStatusController(RateLimitStatusService s) { statusService = s; }

    @GetMapping("/status")
    Map<String, Object> getStatus(HttpServletRequest req) {
        String userId = req.getHeader("X-User-Id");
        String identifier = userId != null ? "user:" + userId : "ip:" + req.getRemoteAddr();
        return statusService.getStatus(identifier);
    }
}

