enum MerchantTier { STARTUP(50), GROWTH(200), ENTERPRISE(2000);
    final int baseLimit;
    MerchantTier(int l){baseLimit=l;}
}
record RateLimitResult(boolean allowed, int limit, long count, long remaining, long resetIn) {}

@Service
class RazorpayRateLimiter {
    private static final Map<String,Double> EP_FACTORS=Map.of(
        "/v1/payments/create",0.5,
        "/v1/refunds",       0.2,
        "/v1/payments",      1.0
    );
    private static final String WHITELIST="rate:whitelist";
    private final RedisTemplate<String,String> redis;
    RazorpayRateLimiter(RedisTemplate<String,String> r){redis=r;}

    void addWhitelist(String id){ redis.opsForSet().add(WHITELIST,id); }
    boolean isWhitelisted(String id){ return Boolean.TRUE.equals(redis.opsForSet().isMember(WHITELIST,id)); }

    RateLimitResult check(String merchantId, MerchantTier tier, String endpoint){
        if(isWhitelisted(merchantId)) return new RateLimitResult(true,tier.baseLimit,0,tier.baseLimit,60);
        double factor=EP_FACTORS.entrySet().stream()
            .filter(e->endpoint.startsWith(e.getKey())).mapToDouble(Map.Entry::getValue)
            .findFirst().orElse(1.0);
        int limit=(int)(tier.baseLimit*factor);
        long window=System.currentTimeMillis()/60_000;
        String key="rate:"+merchantId+":"+endpoint.replace('/','_')+":"+window;
        Long count=redis.opsForValue().increment(key);
        if(count==1) redis.expire(key,Duration.ofMinutes(2));
        long remaining=Math.max(0,limit-count);
        long resetIn=((window+1)*60_000-System.currentTimeMillis())/1000;
        return new RateLimitResult(count<=limit,limit,count,remaining,resetIn);
    }
}

@Component @Order(1)
class RazorpayRateLimitFilter implements Filter {
    private final RazorpayRateLimiter limiter;
    RazorpayRateLimitFilter(RazorpayRateLimiter l){limiter=l;}
    @Override public void doFilter(ServletRequest req,ServletResponse res,FilterChain chain)
            throws IOException,ServletException{
        HttpServletRequest rq=(HttpServletRequest)req;
        HttpServletResponse rs=(HttpServletResponse)res;
        String mid=rq.getHeader("X-Razorpay-Merchant");
        if(mid==null){chain.doFilter(req,res);return;}
        String tierStr=rq.getHeader("X-Merchant-Tier");
        MerchantTier tier;
        try{tier=tierStr!=null?MerchantTier.valueOf(tierStr):MerchantTier.STARTUP;}
        catch(Exception e){tier=MerchantTier.STARTUP;}
        RateLimitResult r=limiter.check(mid,tier,rq.getRequestURI());
        rs.setHeader("X-RateLimit-Limit",String.valueOf(r.limit()));
        rs.setHeader("X-RateLimit-Remaining",String.valueOf(r.remaining()));
        if(!r.allowed()){
            rs.setStatus(429); rs.setContentType("application/json");
            rs.setHeader("Retry-After",String.valueOf(r.resetIn()));
            rs.getWriter().write("{\"error\":\"Rate limit exceeded\"}");
            return;
        }
        chain.doFilter(req,res);
    }
}

